    if (s != s.reversed()) return false

    val count = mutableMapOf<Char, Int>()
    for (c in s) {
        count[c] = count.getOrDefault(c, 0) + 1
    }

    for ((char, cnt) in count) {
        val digit = char.toString().toInt()
        if (digit != cnt) {
            return false
        }
    }

    // Check that all digits present are exactly 1..9 and their counts match
    // Also ensure no extra digits (like 0) are present
    val digits = s.map { it.toString().toInt() }.toSet()
    for (d in digits) {
        if (d == 0) return false
        if (count.getOrDefault(d.toString()[0], 0) != d) {
            return false
        }
    }

    return true
}
